mapper.insert:

    SELECT SEQ_MATERIAL.NEXTVAL FROM DUAL


INSERT INTO MATERIALS(MATERIAL_ID
                    , MATERIAL_NAME
                    , MATERIAL_TYPE
                    , SUPPLY_PRICE
                    , DETAILS)
               VALUES(#{materialId}
                    , #{materialName}
                    , 
                        #{materialType}
                        'ET'

                    , #{supplyPrice}
                    , #{details})

        MERGE INTO MATERIAL_FILES MF
        USING DUAL
           ON (MF.MATERIAL_ID = #{materialId} AND MF.DELETED_AT IS NULL)


          WHEN MATCHED THEN
	    UPDATE
	       SET MF.ORIGINAL_NAME = #{originalName}
	         , MF.STORED_NAME   = #{storedName}
	         , MF.STORAGE_PATH  = #{storagePath}
	         , MF.CREATED_AT    = SYSDATE


       WHEN NOT MATCHED THEN
           INSERT (MF.MATERIAL_FILE_ID
                 , MF.ORIGINAL_NAME
                 , MF.STORED_NAME
                 , MF.STORAGE_PATH
                 , MF.MATERIAL_ID)
            VALUES (SEQ_MAT_FILE.NEXTVAL
                  , #{originalName}
                  , #{storedName}
                  , #{storagePath}
                  , #{materialId})

mapper.update:
UPDATE MATERIALS
   SET MATERIAL_NAME = #{materialName}
     , MATERIAL_TYPE = 
                         #{materialType}
                         'ET'

     , SUPPLY_PRICE  = #{supplyPrice}
     , DETAILS       = #{details}
     , STATUS        = #{status}
     , UPDATED_AT    = SYSDATE
 WHERE MATERIAL_ID   = #{materialId}
   AND STATUS        != 'INACTIVE'
